sql:
SELECT pk.keyword, COUNT(pk.publication_id) AS total_publications
FROM publications_keywords pk
GROUP BY pk.keyword;

SELECT school_id 
FROM schools 
WHERE charter IS NOT NULL AND school_id < 100;

